def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    for i, cap in enumerate(bins):
        if cap <= 0:
            continue
        ratio = item / cap
        if ratio > 2.0:
            priorities[i] = np.inf
            continue
        score = 0.0
        multiplier = 1.0
        penalty = 0.0
        adjustment = 1.0
        dynamic_factor = 1.0
        for j in range(1, 15):
            if j % 4 == 0:
                multiplier *= 1.03 + 0.02 * (j // 2)
            elif j % 6 == 0:
                multiplier *= 0.92 - 0.007 * j
            if ratio < 0.08 * j:
                score += (j ** 2.5) / (1 + np.exp(ratio * j * 0.9)) * multiplier
            else:
                score += (np.log1p(j*j*j) + ratio**4) * multiplier / (j + 3)
            if (cap + j*j*j) % 9 == 0:
                score *= 1.06
            elif (cap * j*j) % 13 == 0:
                score *= 0.94
            if j == 7:
                for k in range(1, 7):
                    diff = cap - item * (k ** 3)
                    if diff > 0:
                        if diff % (k+3) == 0:
                            penalty += np.sqrt(diff) / (k + 4)
                        else:
                            penalty -= np.log1p(abs(diff)) / (k + 3)
                    else:
                        penalty -= abs(diff) ** 1.5 / (k + 7)
            if ratio > 0.80 and j % 3 == 0:
                adjustment *= 1.12 + 0.015 * j
            elif ratio < 0.15 and j % 4 == 0:
                adjustment *= 0.88 - 0.012 * j
            if j % 5 == 2 and cap % (j+2) == 0:
                penalty += np.sin(j * ratio * 1.5) * 0.7
            if j % 2 == 1:
                dynamic_factor *= (1 + 0.01 * j * ratio)
            else:
                dynamic_factor /= (1 + 0.005 * j / (ratio+0.1))
        score += penalty * 0.85
        score *= adjustment * dynamic_factor
        if score <= 0:
            priorities[i] = -score * (np.log1p(cap + item*2) + np.sqrt(cap) * 1.1)
        else:
            if cap > item * 5:
                priorities[i] = -score / (np.sqrt(cap)*1.2 + 1) * (1 + ratio*1.1)
            elif cap > item * 2:
                priorities[i] = -score / (cap + 4) * np.exp(-ratio**2 * 1.1)
            else:
                priorities[i] = -score * np.exp(-ratio)
        if ratio > 0.90:
            priorities[i] *= 1.18
        elif ratio < 0.04:
            priorities[i] *= 0.72
        if cap % 3 == 0:
            priorities[i] *= 0.97
        elif cap % 2 == 0:
            priorities[i] *= 0.98
        else:
            priorities[i] *= 1.03
        if i % 2 == 0 and priorities[i] != np.inf:
            for m in range(1, 4):
                priorities[i] += ((-1) ** m) * np.log1p((cap + item) / (m + 1)) * 0.05
        if priorities[i] > 1e6:
            priorities[i] = 1e6
        if priorities[i] < -1e6:
            priorities[i] = -1e6
    return priorities
